import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ============================================================
  // QUOTE: Empty / fee
  // ============================================================
  it.todo("quote with empty item list returns premium of 5 G (only the processing fee)");

  // ============================================================
  // QUOTE: Single item base premiums + first-insurance + fee
  // ============================================================
  it.todo("quote for a single plain sword (0 years, first quote) returns 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("quote for a single plain amulet (0 years, first quote) returns 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("quote for a single plain staff (0 years, first quote) returns 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("quote for a single plain potion (0 years, first quote) returns 49 G (40 base + 4 first-insurance + 5 fee)");

  // ============================================================
  // QUOTE: Components — base premiums and blocks
  // ============================================================
  it.todo("quote for 2 runes yields base premium 50 G (no block)");
  it.todo("quote for 3 runes yields base premium 60 G (block of 3 applies)");
  it.todo("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)");
  it.todo("quote for 7 runes yields base premium 175 G (per spec example)");
  it.todo("quote for 2 runes + 1 moonstone yields base premium 75 G (no block: different types)");
  it.todo("quote for 3 runes + 3 moonstones yields base premium 120 G (two separate blocks: 60 + 60)");

  // ============================================================
  // QUOTE: Item-specific modifiers (cursed, high enchantment)
  // ============================================================
  it.todo("cursed sword (steel, enchantment 3), 0 years, first quote — premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
  it.todo("sword with exactly enchantment 5 — high-enchantment surcharge applies (+30% of item base)");
  it.todo("sword with enchantment 4 — no high-enchantment surcharge");
  it.todo("sword with exactly enchantment 5 and cursed — both surcharges apply");

  // ============================================================
  // QUOTE: Policy-wide modifiers (loyalty, follow-up)
  // ============================================================
  it.todo("customer with exactly 2 years — loyalty discount applies (-20% of policy base premium)");
  it.todo("customer with 1 year — no loyalty discount");
  it.todo("first-insurance surcharge is +10% per item in the quote, regardless of customer history");
  it.todo("follow-up contract (second quote in scenario) — -15% policy-wide discount applies");

  // ============================================================
  // QUOTE: Modifier scope on multi-item policies
  // ============================================================
  it.todo("policy with cursed sword + plain amulet — cursed surcharge applies to sword's base only: policy base 160 G + 50 G curse = 210 G before further modifiers and fee");

  // ============================================================
  // QUOTE: Rounding (up, in MHPCO's favor)
  // ============================================================
  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
  it.todo("intermediate values are kept as fractions; only the final premium is rounded");

  // ============================================================
  // QUOTE: Integration examples
  // ============================================================
  it.todo("newcomer (0 years) with a cursed steel sword (enchantment 3) — premium 165 G");
  it.todo("long-standing customer (3 years), second quote in scenario, cursed steel sword (enchantment 7) — premium 160 G (100 base + 50 curse + 30 high-ench − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)");

  // ============================================================
  // CLAIM: Deductible
  // ============================================================
  it.todo("regular steel sword (enchantment 3), damage 500 G — payout 400 G (500 − 100 deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G (200 − 100 deductible)");
  it.todo("dragon attack damages a sword (500 G) and an amulet (300 G) — total payout 600 G (deductible applied per damage entry: 400 + 200)");

  // ============================================================
  // CLAIM: High-enchantment (≥ 8) — 50% of damage
  // ============================================================
  it.todo("steel sword, enchantment 9, damage 1000 G — payout 400 G (50% = 500, then − 100 deductible)");

  // ============================================================
  // CLAIM: Dragon material — full reimbursement, dragon clause wins
  // ============================================================
  it.todo("dragon-material sword, enchantment 5, damage 800 G — payout 700 G (full reimbursement, then − 100 deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G — payout 400 G (high-enchantment clause applies, then deductible: 500 − 100) [per spec example]");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G — payout 400 G (50% rule wins, then deductible: 500 − 100) [per spec example]");

  // ============================================================
  // CLAIM: Cap (2× insurance sum, based on unmodified insurance value)
  // ============================================================
  it.todo("policy covering sword + amulet — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (modified premium 165 G) — cap is 2000 G (based on unmodified insurance value 1000 G)");
  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("sword (cap 2000 G), first claim 1500 G — payout 1400 G, remainingCap 600 G");
  it.todo("sword (cap 2000 G), two successive claims of 1500 G — second claim payout 600 G, remainingCap 0 G (reduced to remaining cap)");

  // ============================================================
  // CLAIM: Multiple items of same type
  // ============================================================
  it.todo("policy covers two swords — insurance sum 2000 G, cap 4000 G");
  it.todo("two swords insured, two sword damage entries — each entry is a separate damage with its own deductible");

  // ============================================================
  // CLAIM: Rounding (down, in MHPCO's favor)
  // ============================================================
  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");

  // ============================================================
  // CLI: Basic integration
  // ============================================================
  it.todo("CLI reads JSON from stdin and writes JSON {results: [...]} to stdout");
  it.todo("CLI: scenario with one quote step returns {results: [{premium: <int>}]}");
  it.todo("CLI: scenario with quote then claim returns {results: [{premium}, {payout, remainingCap}]}");

  // ============================================================
  // CLI: Error cases (non-zero exit, stderr message, no stdout results)
  // ============================================================
  it.todo("CLI: quote with unknown item type (e.g. broomstick) exits non-zero and writes error to stderr; no results on stdout");
  it.todo("CLI: claim references an item not in the policy (e.g. amulet damaged when only sword insured) exits non-zero with stderr error");
  it.todo("CLI: claim contains a damage entry with negative amount exits non-zero with stderr error");
  it.todo("CLI: claim has more damage entries of a type than items insured (e.g. 2 sword damages, 1 sword) exits non-zero with stderr error");
});

